const fs = require('fs');
const path = require('path');

const PROBLEMS_FILE = path.resolve(__dirname, '../../data/problems.json');

function loadProblems() {
  const raw = fs.readFileSync(PROBLEMS_FILE, 'utf8');
  return JSON.parse(raw);
}

/**
 * Get problems list with filtering, paging, sorting, and metadata.
 * @param {Object} options
 * @param {string} [options.difficulty] - difficulty filter, e.g. 'Easy', 'Medium', 'Hard'
 * @param {boolean} [options.includeComponents] - whether to include sorted componentLanguages
 * @param {number} [options.limit=50] - max number of results to return, capped at 50
 * @returns {Object} result with problems array and metadata
 */
function getProblems(options = {}) {
  const difficultyFilter = options.difficulty;
  const includeComponents = options.includeComponents || false;
  const limit = Math.min(options.limit || 50, 50);

  const allProblems = loadProblems();

  // Filter by difficulty if specified
  let filtered = difficultyFilter
    ? allProblems.filter(p => p.difficulty === difficultyFilter)
    : allProblems.slice();

  // Sort by roundId ascending for deterministic order
  filtered.sort((a, b) => {
    if (a.roundId < b.roundId) return -1;
    if (a.roundId > b.roundId) return 1;
    return 0;
  });

  // Apply limit
  const limited = filtered.slice(0, limit);

  // Prepare difficulty breakdown
  const difficultyBreakdown = {};
  for (const p of allProblems) {
    difficultyBreakdown[p.difficulty] = (difficultyBreakdown[p.difficulty] || 0) + 1;
  }

  // Prepare problems output
  const problems = limited.map(p => {
    const problem = {
      problemId: p.problemId,
      roundId: p.roundId,
      difficulty: p.difficulty,
      name: p.name,
    };
    if (includeComponents && Array.isArray(p.componentLanguages)) {
      problem.componentLanguages = p.componentLanguages.slice().sort();
    }
    return problem;
  });

  return {
    problems,
    totalProblems: allProblems.length,
    filteredCount: filtered.length,
    appliedLimit: limit,
    difficultyBreakdown,
  };
}

function solve(...args) {
  return getProblems(...args);
